template <typename T>
__device__ __forceinline__ T zero_val() {
    return (T)0;
}

template <>
__device__ __forceinline__ __half2 zero_val<__half2>() {
    return __float2half2_rn(0.0f);
}

template <typename T>
__device__ __forceinline__ T neg_one_val() {
    return (T)-1;
}

template <>
__device__ __forceinline__ __half2 neg_one_val<__half2>() {
    return __float2half2_rn(-1.0f);
}

template <typename T>
__device__ __forceinline__ T add_op(T a, T b) {
    return a + b;
}

template <>
__device__ __forceinline__ __half2 add_op(__half2 a, __half2 b) {
    return __hadd2(a, b);
}

template <typename T>
__device__ __forceinline__ T mul_op(T a, T b) {
    return a * b;
}

template <>
__device__ __forceinline__ __half2 mul_op(__half2 a, __half2 b) {
    return __hmul2(a, b);
}

template <typename T>
__device__ __forceinline__ bool is_equal_op(T a, T b) {
    return a == b;
}

template <>
__device__ __forceinline__ bool is_equal_op(__half2 a, __half2 b) {
    float2 fa = __half22float2(a);
    float2 fb = __half22float2(b);
    return fa.x == fb.x && fa.y == fb.y;
}

template <typename T, int COMPUTE_ITERATIONS, bool BLOCK_STRIDED, int ELEMENTS_PER_THREAD, int FUSION_DEGREE>
__global__ void benchmark_kernel(T seed, T* g_data, long total_threads) {
    const unsigned int blockSize = blockDim.x;
    const long global_id = (long)blockIdx.x * (long)blockDim.x + (long)threadIdx.x;
    if (global_id >= total_threads) return;

    long stride, idx;
    if (BLOCK_STRIDED) {
        stride = (long)blockSize;
        idx = (long)blockIdx.x * (long)blockSize * (long)ELEMENTS_PER_THREAD + (long)threadIdx.x;
    } else {
        stride = total_threads;
        idx = global_id;
    }
    const long big_stride = (long)gridDim.x * (long)blockSize * (long)ELEMENTS_PER_THREAD;

    T tmps[ELEMENTS_PER_THREAD];

#pragma unroll
    for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + (long)j * stride + (long)k * big_stride];
#pragma unroll
            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = add_op(mul_op(tmps[j], tmps[j]), seed);
            }
        }

        T sum = zero_val<T>();
#pragma unroll
        for (int j = 0; j + 1 < ELEMENTS_PER_THREAD; j += 2) {
            sum = add_op(sum, mul_op(tmps[j], tmps[j + 1]));
        }

        if (is_equal_op(sum, neg_one_val<T>())) {
            g_data[idx + (long)k * big_stride] = sum;
        }
    }
}

#define DISPATCH_KERNEL_CASE(CI) \
