static inline void cuda_throw(cudaError_t err, const char* where)
{
	if (err != cudaSuccess)
	{
		throw std::string(where) + cudaGetErrorString(err);
	}
}

template <typename T>
T* alloc(int N)
{
	T* mem_d = 0;
	cuda_throw(cudaMalloc((void**)&mem_d, sizeof(T) * N), "cudaMalloc failed: ");
	return mem_d;
}

template <typename T>
void dealloc(T* array)
{
	if (array) cudaFree((void*)array);
}

template <typename T>
void copy(T* dst, T* src, int N)
{
	cuda_throw(cudaMemcpy(dst, src, N * sizeof(T), cudaMemcpyDeviceToDevice), "cudaMemcpy D2D failed: ");
}

template <typename T>
void upload(T* dst, T* src, int N)
{
	cuda_throw(cudaMemcpy(dst, src, N * sizeof(T), cudaMemcpyHostToDevice), "cudaMemcpy H2D failed: ");
}

template <typename T>
void download(T* dst, T* src, int N)
{
	cuda_throw(cudaMemcpy(dst, src, N * sizeof(T), cudaMemcpyDeviceToHost), "cudaMemcpy D2H failed: ");
}

