static double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5)
        return newValue;
    else
        return newValue++;
}

static void setIf(int testValue, int newValue, int *array3D, int *dimX, int *dimY, int *dimZ) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

static double randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double)M));
}

static double randn(int *seed, int index) {
    double u1 = randu(seed, index);
    double v1 = randu(seed, index);
    double cosine = cos(2 * PI * v1);
    double rt = -2 * log(u1);
    return sqrt(rt) * cosine;
}

static void addNoise(int *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (int)(5 * randn(seed, 0));
            }
        }
    }
}

static void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if (distance < radius) disk[x * diameter + y] = 1;
        }
    }
}

static void dilate_matrix(int *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;
    for (int x = startX; x < endX; x++) {
        for (int y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

static void imdilate_disk(int *matrix, int dimX, int dimY, int dimZ, int error, int *newMatrix) {
    for (int z = 0; z < dimZ; z++) {
        for (int x = 0; x < dimX; x++) {
            for (int y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1)
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
            }
        }
    }
}

static void getneighbors(int *se, int numOnes, double *neighbors, int radius) {
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

static void videoSequence(int *I, int IszX, int IszY, int Nfr, int *seed) {
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    for (int k = 1; k < Nfr; k++) {
        int xk = abs(x0 + (k - 1));
        int yk = abs(y0 - 2 * (k - 1));
        int pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size) pos = 0;
        I[pos] = 1;
    }

    int *newMatrix = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

static double calcLikelihoodSum(int *I, int *indv, int numOnes) {
    double likelihoodSum = 0.0;
    for (int y = 0; y < numOnes; y++)
        likelihoodSum += (pow((double)(I[indv[y]] - 100), 2) - pow((double)(I[indv[y]] - 228), 2)) / 50.0;
    return likelihoodSum;
}

__global__ void particle_kernel(double *arrayX_d, double *arrayY_d, double *CDF_d, double *u_d, double *xj_d, double *yj_d, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF_d[x] >= u_d[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) index = Nparticles - 1;
        xj_d[i] = arrayX_d[index];
        yj_d[i] = arrayY_d[index];
    }
}

