static inline void check_cuda(cudaError_t e) {
    if (e != cudaSuccess) {
        printf("CUDA error: %s\n", cudaGetErrorString(e));
        exit(1);
    }
}

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

double elapsed_time(long long start_time, long long end_time) {
    return (double)(end_time - start_time) / (1000.0 * 1000.0);
}

template <typename T>
T randu_host(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return (T)fabs(seed[index] / ((double)M));
}

template <typename T>
T randn_host(int *seed, int index) {
    T u = randu_host<T>(seed, index);
    T v = randu_host<T>(seed, index);
    T cosine = (T)cos((T)2 * (T)PI * v);
    T rt = (T)-2 * (T)log((double)u);
    return (T)sqrt((double)rt) * cosine;
}

template <typename T>
T round_host(T value) {
    int newValue = (int)(value);
    if ((T).5 > value - (T)newValue)
        return (T)newValue;
    else
        return (T)(newValue++);
}

template <typename PixelT>
void setIf(int testValue, int newValue, PixelT *array3D, int *dimX, int *dimY, int *dimZ) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                if ((int)array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = (PixelT)newValue;
            }
        }
    }
}

template <typename PixelT, typename RealT>
void addNoise(PixelT *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    (PixelT)(array3D[x * *dimY * *dimZ + y * *dimZ + z] + (PixelT)(5 * randn_host<RealT>(seed, 0)));
            }
        }
    }
}

template <typename RealT>
void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            RealT dx = (RealT)(x - radius + 1);
            RealT dy = (RealT)(y - radius + 1);
            RealT distance = (RealT)sqrt((double)(dx * dx + dy * dy));
            if ((RealT)radius > distance)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

template <typename PixelT, typename RealT>
void dilate_matrix(PixelT *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (0 > startX) startX++;
    int startY = posY - error;
    while (0 > startY) startY++;
    int endX = posX + error;
    while (dimX < endX) endX--;
    int endY = posY + error;
    while (dimY < endY) endY--;

    for (int x = startX; x < endX; x++) {
        for (int y = startY; y < endY; y++) {
            RealT dx = (RealT)(x - posX);
            RealT dy = (RealT)(y - posY);
            RealT distance = (RealT)sqrt((double)(dx * dx + dy * dy));
            if ((RealT)error > distance)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = (PixelT)1;
        }
    }
}

template <typename PixelT, typename RealT>
void imdilate_disk(PixelT *matrix, int dimX, int dimY, int dimZ, int error, PixelT *newMatrix) {
    for (int z = 0; z < dimZ; z++) {
        for (int x = 0; x < dimX; x++) {
            for (int y = 0; y < dimY; y++) {
                if ((int)matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix<PixelT, RealT>(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors_int(int *se, int numOnes, int *neighbors, int radius) {
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void getneighbors_double(int *se, int numOnes, double *neighbors, int radius) {
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

template <typename PixelT, typename RealT>
void videoSequence(PixelT *I, int IszX, int IszY, int Nfr, int *seed) {
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)round_host<RealT>((RealT)IszY / (RealT)2.0);
    int y0 = (int)round_host<RealT>((RealT)IszX / (RealT)2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = (PixelT)1;

    for (int k = 1; k < Nfr; k++) {
        int xk = abs(x0 + (k - 1));
        int yk = abs(y0 - 2 * (k - 1));
        int pos = yk * IszY * Nfr + xk * Nfr + k;
        if (max_size <= pos) pos = 0;
        I[pos] = (PixelT)1;
    }

    PixelT *newMatrix = (PixelT *)calloc(IszX * IszY * Nfr, sizeof(PixelT));
    imdilate_disk<PixelT, RealT>(I, IszX, IszY, Nfr, 5, newMatrix);

    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf<PixelT>(0, 100, I, &IszX, &IszY, &Nfr);
    setIf<PixelT>(1, 228, I, &IszX, &IszY, &Nfr);

    addNoise<PixelT, RealT>(I, &IszX, &IszY, &Nfr, seed);
}

double calcLikelihoodSum_cpu_int(int *I, int *ind, int numOnes) {
    double likelihoodSum = 0.0;
    for (int y = 0; y < numOnes; y++) {
        double a = (double)(I[ind[y]] - 100);
        double b = (double)(I[ind[y]] - 228);
        likelihoodSum = likelihoodSum + ((a * a - b * b) / 50.0);
    }
    return likelihoodSum;
}

__global__ void particle_kernel_naive(double *elem_6, double *x_1, double *x_15, double *u, double *data_10, double *x_12, int item_5) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (item_5 > i) {
        int elem_8 = -1;
        for (int x = 0; item_5 > x; x++) {
            if (u[i] <= x_15[x]) {
                elem_8 = x;
                break;
            }
        }
        if (-1 == elem_8) {
            elem_8 = item_5 - 1;
        }
        data_10[i] = elem_6[elem_8];
        x_12[i] = x_1[elem_8];
    }
}

template <typename T>
__device__ T dev_round_dev(T value) {
    int newValue = (int)(value);
    if (value - (T)newValue < (T).5f)
        return (T)newValue;
    else
        return (T)(newValue++);
}

template <typename T>
__device__ T d_randu_dev(int *seed, int index) {
    int Mloc = INT_MAX;
    int Aloc = 1103515245;
    int Cloc = 12345;
    int num = Aloc * seed[index] + Cloc;
    seed[index] = num % Mloc;
    return (T)fabs(seed[index] / ((double)Mloc));
}

template <typename T>
__device__ T d_randn_dev(int *seed, int index) {
    T pi = (T)3.14159265358979323846;
    T u = d_randu_dev<T>(seed, index);
    T v = d_randu_dev<T>(seed, index);
    T cosine = (T)cos((T)2 * pi * v);
    T rt = (T)-2 * (T)log((double)u);
    return (T)sqrt((double)rt) * cosine;
}

template <typename T>
__device__ T calcLikelihoodSum_dev(unsigned char *I, int *ind, int numOnes, int index) {
    T likelihoodSum = (T)0.0;
    for (int x = 0; x < numOnes; x++) {
        T a = (T)(I[ind[index * numOnes + x]] - 100);
        T b = (T)(I[ind[index * numOnes + x]] - 228);
        likelihoodSum += ((a * a - b * b) / (T)50.0);
    }
    return likelihoodSum;
}

template <typename T>
__device__ void cdfCalc_dev(T *CDF, T *weights, int Nparticles) {
    CDF[0] = weights[0];
    for (int x = 1; x < Nparticles; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

template <typename T>
__global__ void find_index_kernel_cuda(T *arrayX, T *arrayY, T *CDF, T *u, T *xj, T *yj, T *weights, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;

    if (i < Nparticles) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }

        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

template <typename T>
__global__ void normalize_weights_kernel_cuda(T *weights, int Nparticles, T *partial_sums, T *CDF, T *u, int *seed) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int local_id = threadIdx.x;
    __shared__ T u1;
    __shared__ T sumWeights;

    if (0 == local_id)
        sumWeights = partial_sums[0];

    __syncthreads();

    if (i < Nparticles) {
        weights[i] = weights[i] / sumWeights;
    }

    __syncthreads();

    if (i == 0) {
        cdfCalc_dev<T>(CDF, weights, Nparticles);
        u[0] = ((T)1 / ((T)(Nparticles))) * d_randu_dev<T>(seed, i);
    }

    __syncthreads();

    if (0 == local_id)
        u1 = u[0];

    __syncthreads();

    if (i < Nparticles) {
        u[i] = u1 + i / ((T)(Nparticles));
    }
}

template <typename T>
__global__ void sum_kernel_cuda(T *partial_sums, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    size_t THREADS_PER_BLOCK = blockDim.x;

    if (i == 0) {
        T sum = (T)0;
        int num_blocks = (int)ceil((double)Nparticles / (double)THREADS_PER_BLOCK);
        for (int x = 0; x < num_blocks; x++) {
            sum += partial_sums[x];
        }
        partial_sums[0] = sum;
    }
}

template <typename T, bool USE_SCALE>
__global__ void likelihood_kernel_cuda(T *arrayX, T *arrayY, T *xj, T *yj, T *CDF, int *ind, int *objxy, T *likelihood, unsigned char *I, T *u, T *weights, const int Nparticles, const int countOnes, const int max_size, int k, const int IszY, const int Nfr, int *seed, T *partial_sums) {
    int block_id = blockIdx.x;
    int thread_id = threadIdx.x;
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    size_t THREADS_PER_BLOCK = blockDim.x;
    int indX, indY;

    extern __shared__ unsigned char shared_raw[];
    T *buffer = (T *)shared_raw;

    if (i < Nparticles) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];

        weights[i] = (T)1 / ((T)(Nparticles));

        arrayX[i] = arrayX[i] + (T)1.0 + (T)5.0 * d_randn_dev<T>(seed, i);
        arrayY[i] = arrayY[i] - (T)2.0 + (T)2.0 * d_randn_dev<T>(seed, i);
    }

    __syncthreads();

    if (i < Nparticles) {
        for (int y = 0; y < countOnes; y++) {
            indX = (int)dev_round_dev<T>(arrayX[i]) + objxy[y * 2 + 1];
            indY = (int)dev_round_dev<T>(arrayY[i]) + objxy[y * 2];

            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum_dev<T>(I, ind, countOnes, i);
        if (USE_SCALE)
            likelihood[i] = likelihood[i] / (T)countOnes - (T)SCALE_FACTOR;
        else
            likelihood[i] = likelihood[i] / (T)countOnes;

        weights[i] = weights[i] * (T)exp((double)likelihood[i]);
    }

    buffer[thread_id] = (T)0.0;

    __syncthreads();

    if (i < Nparticles) {
        buffer[thread_id] = weights[i];
    }

    __syncthreads();

    for (unsigned int s = THREADS_PER_BLOCK / 2; s > 0; s >>= 1) {
        if (thread_id < (int)s) {
            buffer[thread_id] += buffer[thread_id + s];
        }
        __syncthreads();
    }
    if (thread_id == 0) {
        partial_sums[block_id] = buffer[0];
    }
}

static void initialize_cuda_common(int print_platform_info, int *tpb) {
    int device_count = 0;
    check_cuda(cudaGetDeviceCount(&device_count));
    if (print_platform_info) {
        printf("number of available platforms:%d.\n", device_count);
        printf("clGetPlatformInfo: NVIDIA CUDA\n");
    }
    if (device_count <= 0) {
        printf("ERROR: no CUDA devices found\n");
        exit(1);
    }
    if (device_id_inuse < 0 || device_id_inuse >= device_count)
        device_id_inuse = 0;
    check_cuda(cudaSetDevice(device_id_inuse));
    cudaDeviceProp prop;
    check_cuda(cudaGetDeviceProperties(&prop, device_id_inuse));
    if (tpb && *tpb > prop.maxThreadsPerBlock)
        *tpb = prop.maxThreadsPerBlock;
}

int particleFilter_naive(int *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    long long start = get_time();

    initialize_cuda_common(0, NULL);

    double xe = round_host<double>(IszY / 2.0);
    double ye = round_host<double>(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)malloc(diameter * diameter * sizeof(int));
    strelDisk<double>(disk, radius);
    int countOnes = 0;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (1 == disk[x * diameter + y])
                countOnes++;
        }
    }
    double *objxy = (double *)malloc(countOnes * 2 * sizeof(double));
    getneighbors_double(disk, countOnes, objxy, radius);

    long long get_neighbors = get_time();
    printf("TIME TO GET NEIGHBORS TOOK: %f\n", elapsed_time(start, get_neighbors));

    double *weights = (double *)malloc(sizeof(double) * Nparticles);
    for (int x = 0; x < Nparticles; x++) {
        weights[x] = 1 / ((double)(Nparticles));
    }
    long long get_weights = get_time();
    printf("TIME TO GET WEIGHTSTOOK: %f\n", elapsed_time(get_neighbors, get_weights));

    double *likelihood = (double *)malloc(sizeof(double) * Nparticles);
    double *arrayX = (double *)malloc(sizeof(double) * Nparticles);
    double *arrayY = (double *)malloc(sizeof(double) * Nparticles);
    double *xj = (double *)malloc(sizeof(double) * Nparticles);
    double *yj = (double *)malloc(sizeof(double) * Nparticles);
    double *CDF = (double *)malloc(sizeof(double) * Nparticles);
    int *ind = (int *)malloc(sizeof(int) * countOnes);
    double *u = (double *)malloc(sizeof(double) * Nparticles);

    double *arrayX_GPU;
    double *arrayY_GPU;
    double *xj_GPU;
    double *yj_GPU;
    double *CDF_GPU;
    double *u_GPU;

    check_cuda(cudaMalloc((void **)&arrayX_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&arrayY_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&xj_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&yj_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&CDF_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&u_GPU, sizeof(double) * Nparticles));

    for (int x = 0; x < Nparticles; x++) {
        arrayX[x] = xe;
        arrayY[x] = ye;
    }

    for (int k = 1; k < Nfr; k++) {
        long long set_arrays = get_time();

        for (int x = 0; x < Nparticles; x++) {
            arrayX[x] = arrayX[x] + 1.0 + 5.0 * randn_host<double>(seed, x);
            arrayY[x] = arrayY[x] - 2.0 + 2.0 * randn_host<double>(seed, x);
        }

        long long error = get_time();
        printf("TIME TO SET ERROR TOOK: %f\n", elapsed_time(set_arrays, error));

        for (int x = 0; x < Nparticles; x++) {
            for (int y = 0; y < countOnes; y++) {
                int indX = (int)round_host<double>(arrayX[x]) + (int)objxy[y * 2 + 1];
                int indY = (int)round_host<double>(arrayY[x]) + (int)objxy[y * 2];
                ind[y] = (int)fabs((double)(indX * IszY * Nfr + indY * Nfr + k));
                if (max_size <= ind[y])
                    ind[y] = 0;
            }
            likelihood[x] = calcLikelihoodSum_cpu_int(I, ind, countOnes);
            likelihood[x] = likelihood[x] / countOnes;
        }

        long long likelihood_time = get_time();
        printf("TIME TO GET LIKELIHOODS TOOK: %f\n", elapsed_time(error, likelihood_time));

        for (int x = 0; x < Nparticles; x++) {
            weights[x] = weights[x] * exp(likelihood[x]);
        }

        long long exponential = get_time();
        printf("TIME TO GET EXP TOOK: %f\n", elapsed_time(likelihood_time, exponential));

        double sumWeights = 0;
        for (int x = 0; x < Nparticles; x++) {
            sumWeights = sumWeights + (weights[x]);
        }

        long long sum_time = get_time();
        printf("TIME TO SUM WEIGHTS TOOK: %f\n", elapsed_time(exponential, sum_time));

        for (int x = 0; x < Nparticles; x++) {
            weights[x] = weights[x] / sumWeights;
        }

        long long normalize = get_time();
        printf("TIME TO NORMALIZE WEIGHTS TOOK: %f\n", elapsed_time(sum_time, normalize));

        xe = 0;
        ye = 0;
        for (int x = 0; x < Nparticles; x++) {
            xe = xe + (arrayX[x] * weights[x]);
            ye = ye + (arrayY[x] * weights[x]);
        }

        long long move_time = get_time();
        printf("TIME TO MOVE OBJECT TOOK: %f\n", elapsed_time(normalize, move_time));
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        double distance = sqrt(pow((double)(xe - (int)round_host<double>(IszY / 2.0)), 2) +
                               pow((double)(ye - (int)round_host<double>(IszX / 2.0)), 2));
        printf("%lf\n", distance);

        CDF[0] = weights[0];
        for (int x = 1; x < Nparticles; x++) {
            CDF[x] = weights[x] + CDF[x - 1];
        }

        long long cum_sum = get_time();
        printf("TIME TO CALC CUM SUM TOOK: %f\n", elapsed_time(move_time, cum_sum));

        double u1 = (1 / ((double)(Nparticles))) * randu_host<double>(seed, 0);
        for (int x = 0; x < Nparticles; x++) {
            u[x] = u1 + x / ((double)(Nparticles));
        }

        long long u_time = get_time();
        printf("TIME TO CALC U TOOK: %f\n", elapsed_time(cum_sum, u_time));

        long long start_copy = get_time();

        check_cuda(cudaMemcpy(arrayX_GPU, arrayX, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(arrayY_GPU, arrayY, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(CDF_GPU, CDF, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(u_GPU, u, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));

        long long end_copy = get_time();

        int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block_naive);

        particle_kernel_naive<<<num_blocks, threads_per_block_naive>>>(arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, Nparticles);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        long long start_copy_back = get_time();

        check_cuda(cudaMemcpy(yj, yj_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
        check_cuda(cudaMemcpy(xj, xj_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));

        long long end_copy_back = get_time();

        printf("SENDING TO GPU TOOK: %lf\n", elapsed_time(start_copy, end_copy));
        printf("OPEN_CL EXEC TOOK: %lf\n", elapsed_time(end_copy, start_copy_back));
        printf("SENDING BACK FROM GPU TOOK: %lf\n", elapsed_time(start_copy_back, end_copy_back));

        long long xyj_time = get_time();
        printf("TIME TO CALC NEW ARRAY X AND Y TOOK: %f\n", elapsed_time(u_time, xyj_time));

        for (int x = 0; x < Nparticles; x++) {
            arrayX[x] = xj[x];
            arrayY[x] = yj[x];
            weights[x] = 1 / ((double)(Nparticles));
        }

        long long reset = get_time();
        printf("TIME TO RESET WEIGHTS TOOK: %f\n", elapsed_time(xyj_time, reset));
    }

    cudaFree(u_GPU);
    cudaFree(CDF_GPU);
    cudaFree(yj_GPU);
    cudaFree(xj_GPU);
    cudaFree(arrayY_GPU);
    cudaFree(arrayX_GPU);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(xj);
    free(yj);
    free(arrayX);
    free(arrayY);
    free(CDF);
    free(u);
    free(ind);

    return 0;
}

template <typename T, bool USE_SCALE>
int particleFilter_fd(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int local_threads_per_block = threads_per_block;
    initialize_cuda_common(1, &local_threads_per_block);

    int max_size = IszX * IszY * Nfr;

    T xe = round_host<T>((T)IszY / (T)2.0);
    T ye = round_host<T>((T)IszX / (T)2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)calloc(diameter * diameter, sizeof(int));
    strelDisk<T>(disk, radius);

    int countOnes = 0;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (1 == disk[x * diameter + y])
                countOnes++;
        }
    }

    int *objxy = (int *)calloc(countOnes * 2, sizeof(int));
    getneighbors_int(disk, countOnes, objxy, radius);

    T *weights = (T *)calloc(Nparticles, sizeof(T));
    for (int x = 0; x < Nparticles; x++) {
        weights[x] = (T)1 / ((T)(Nparticles));
    }

    T *likelihood = (T *)calloc(Nparticles + 1, sizeof(T));
    T *arrayX = (T *)calloc(Nparticles, sizeof(T));
    T *arrayY = (T *)calloc(Nparticles, sizeof(T));
    T *xj = (T *)calloc(Nparticles, sizeof(T));
    T *yj = (T *)calloc(Nparticles, sizeof(T));
    T *CDF = (T *)calloc(Nparticles, sizeof(T));
    int *ind = (int *)calloc(countOnes, sizeof(int));
    T *u = (T *)calloc(Nparticles, sizeof(T));

    T *arrayX_GPU;
    T *arrayY_GPU;
    T *xj_GPU;
    T *yj_GPU;
    T *CDF_GPU;
    T *likelihood_GPU;
    unsigned char *I_GPU;
    T *weights_GPU;
    int *objxy_GPU;
    int *ind_GPU;
    T *u_GPU;
    int *seed_GPU;
    T *partial_sums;

    check_cuda(cudaMalloc((void **)&arrayX_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&arrayY_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&xj_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&yj_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&CDF_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&u_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&likelihood_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&weights_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&I_GPU, sizeof(unsigned char) * IszX * IszY * Nfr));
    check_cuda(cudaMalloc((void **)&objxy_GPU, 2 * sizeof(int) * countOnes));
    check_cuda(cudaMalloc((void **)&ind_GPU, sizeof(int) * countOnes * Nparticles));
    check_cuda(cudaMalloc((void **)&seed_GPU, sizeof(int) * Nparticles));
    check_cuda(cudaMalloc((void **)&partial_sums, sizeof(T) * (Nparticles + 1)));
    check_cuda(cudaMemset(partial_sums, 0, sizeof(T) * (Nparticles + 1)));

    for (int x = 0; x < Nparticles; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    long long send_start = get_time();

    check_cuda(cudaMemcpy(I_GPU, I, sizeof(unsigned char) * IszX * IszY * Nfr, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(objxy_GPU, objxy, 2 * sizeof(int) * countOnes, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(weights_GPU, weights, sizeof(T) * Nparticles, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(xj_GPU, xj, sizeof(T) * Nparticles, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(yj_GPU, yj, sizeof(T) * Nparticles, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(seed_GPU, seed, sizeof(int) * Nparticles, cudaMemcpyHostToDevice));

    long long send_end = get_time();
    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));

    int num_blocks = (int)ceil((double)Nparticles / (double)local_threads_per_block);
    printf("threads_per_block=%d \n", local_threads_per_block);

    for (int k = 1; k < Nfr; k++) {
        likelihood_kernel_cuda<T, USE_SCALE><<<num_blocks, local_threads_per_block, local_threads_per_block * sizeof(T)>>>(
            arrayX_GPU, arrayY_GPU, xj_GPU, yj_GPU, CDF_GPU, ind_GPU, objxy_GPU, likelihood_GPU, I_GPU, u_GPU,
            weights_GPU, Nparticles, countOnes, max_size, k, IszY, Nfr, seed_GPU, partial_sums);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        sum_kernel_cuda<T><<<num_blocks, local_threads_per_block>>>(partial_sums, Nparticles);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        normalize_weights_kernel_cuda<T><<<num_blocks, local_threads_per_block>>>(
            weights_GPU, Nparticles, partial_sums, CDF_GPU, u_GPU, seed_GPU);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        check_cuda(cudaMemcpy(arrayX, arrayX_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
        check_cuda(cudaMemcpy(arrayY, arrayY_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
        check_cuda(cudaMemcpy(weights, weights_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));

        xe = (T)0;
        ye = (T)0;
        T total = (T)0.0;
        for (int x = 0; x < Nparticles; x++) {
            xe = xe + (arrayX[x] * weights[x]);
            ye = ye + (arrayY[x] * weights[x]);
            total = total + (weights[x]);
        }

        printf("total weight: %lf\n", (double)total);
        printf("XE: %lf\n", (double)xe);
        printf("YE: %lf\n", (double)ye);
        T distance = (T)sqrt(pow((double)(xe - (int)round_host<T>((T)IszY / (T)2.0)), 2) +
                             pow((double)(ye - (int)round_host<T>((T)IszX / (T)2.0)), 2));
        printf("%lf\n", (double)distance);

        find_index_kernel_cuda<T><<<num_blocks, local_threads_per_block>>>(
            arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, weights_GPU, Nparticles);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());
    }

    long long back_time = get_time();

    cudaFree(u_GPU);
    cudaFree(CDF_GPU);
    cudaFree(yj_GPU);
    cudaFree(xj_GPU);
    cudaFree(likelihood_GPU);
    cudaFree(I_GPU);
    cudaFree(objxy_GPU);
    cudaFree(ind_GPU);
    cudaFree(seed_GPU);
    cudaFree(partial_sums);

    long long free_time = get_time();

    check_cuda(cudaMemcpy(arrayX, arrayX_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayX_time = get_time();
    check_cuda(cudaMemcpy(arrayY, arrayY_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayY_time = get_time();
    check_cuda(cudaMemcpy(weights, weights_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
    long long back_end_time = get_time();

    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("SEND TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = (T)0;
    ye = (T)0;
    for (int x = 0; x < Nparticles; x++) {
        xe = xe + (arrayX[x] * weights[x]);
        ye = ye + (arrayY[x] * weights[x]);
    }
    T distance = (T)sqrt(pow((double)(xe - (int)round_host<T>((T)IszY / (T)2.0)), 2) +
                         pow((double)(ye - (int)round_host<T>((T)IszX / (T)2.0)), 2));

    FILE *fid = fopen("output.txt", "w+");
    if (NULL == fid) {
        printf("The file was not opened for writing\n");
        exit(1);
    }
    fprintf(fid, "XE: %lf\n", (double)xe);
    fprintf(fid, "YE: %lf\n", (double)ye);
    fprintf(fid, "distance: %lf\n", (double)distance);
    fclose(fid);

    cudaFree(weights_GPU);
    cudaFree(arrayY_GPU);
    cudaFree(arrayX_GPU);

    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);

    return 0;
}

static const char *base_name(const char *path) {
    const char *p = strrchr(path, '/');
    return p ? p + 1 : path;
}

int main(int argc, char *argv[]) {
    const char *prog = base_name(argv[0]);
    int mode = 0; /* 0=double, 1=float, 2=naive */
    if (strstr(prog, "naive") != NULL)
        mode = 2;
    else if (strstr(prog, "float") != NULL)
        mode = 1;
    else if (strstr(prog, "double") != NULL)
        mode = 0;
    else
        mode = 0;

    const char *usage =
        (mode == 2) ? "naive.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]" :
        (mode == 1) ? "float.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]" :
                      "double.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]";

    if (argc < 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (0 >= IszX) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (0 >= IszY) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (0 >= Nfr) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (0 >= Nparticles) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    for (int i = 9; argc > i; ++i) {
        switch (argv[i][1]) {
            case 'p':
                if (++i < argc) sscanf(argv[i], "%d", &platform_id_inuse);
                break;
            case 'd':
                if (++i < argc) sscanf(argv[i], "%d", &device_id_inuse);
                break;
            default:
                ;
        }
    }

    if (mode == 2) {
        int *seed = (int *)malloc(sizeof(int) * Nparticles);
        for (int i = 0; i < Nparticles; i++)
            seed[i] = (int)time(0) * i;

        int *I = (int *)calloc(IszX * IszY * Nfr, sizeof(int));
        long long start = get_time();

        videoSequence<int, double>(I, IszX, IszY, Nfr, seed);
        long long endVideoSequence = get_time();
        printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

        particleFilter_naive(I, IszX, IszY, Nfr, seed, Nparticles);
        long long endParticleFilter = get_time();
        printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
        printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

        free(seed);
        free(I);
        return 0;
    } else if (mode == 1) {
        int *seed = (int *)calloc(Nparticles, sizeof(int));
        for (int i = 0; i < Nparticles; i++)
            seed[i] = i + 1;

        unsigned char *I = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));
        long long start = get_time();

        videoSequence<unsigned char, float>(I, IszX, IszY, Nfr, seed);
        long long endVideoSequence = get_time();
        printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

        particleFilter_fd<float, true>(I, IszX, IszY, Nfr, seed, Nparticles);
        long long endParticleFilter = get_time();
        printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
        printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

        free(seed);
        free(I);
