void center_print(const char *s, int width)
{
	int length = (int) strlen(s);
	int i;
	for (i = 0; i <= (width-length)/2; i++) {
		fputs(" ", stdout);
	}
	fputs(s, stdout);
	fputs("\n", stdout);
}

