static int validate_and_print_results_opencl(Input input, double runtime, unsigned long vhash, double sim_runtime)
{
	int lookups = 0;
	if( input.simulation_method == HISTORY_BASED )
		lookups = input.lookups*input.particles;
	else
		lookups = input.lookups;
	int lookups_per_sec = (int) ((double) lookups / runtime);
	int sim_only_lookups_per_sec = (int) ((double) lookups / sim_runtime);
	printf("NOTE: Timings are estimated -- use nvprof/nsys/iprof/rocprof for formal analysis\n");
	printf("Total Time Statistics (OpenCL Init / JIT Compilation + Simulation Kernel)\n");
	printf("Runtime:     %.3lf seconds\n", runtime);
	printf("Lookups:     "); fancy_int(lookups);
	printf("Lookups/s:   ");
	fancy_int(lookups_per_sec);
	printf("Simulation Kernel Only Statistics\n");
	printf("Runtime:     %.3lf seconds\n", sim_runtime);
	printf("Lookups/s:   ");
	fancy_int(sim_only_lookups_per_sec);

	int is_invalid = 1;

	unsigned long long large = 0;
	unsigned long long small = 0;
	if(input.simulation_method == HISTORY_BASED )
	{
		large = 351485;
		small = 879693;
	}
	else if( input.simulation_method == EVENT_BASED )
	{
		large = 358389;
		small = 880018;
	}

	if( input.HM  == LARGE )
	{
		if( large == vhash )
		{
			printf("Verification checksum: %lu (Valid)\n", vhash);
			is_invalid = 0;
		}
		else
			printf("Verification checksum: %lu (WARNING - INAVALID CHECKSUM!)\n", vhash);
	}
	else if( input.HM  == SMALL )
	{
		if( small == vhash )
		{
			printf("Verification checksum: %lu (Valid)\n", vhash);
			is_invalid = 0;
		}
		else
			printf("Verification checksum: %lu (WARNING - INAVALID CHECKSUM!)\n", vhash);
	}

	return is_invalid;
}

